#ak-loading .loading {
  width: 50px;
  height: 50px;
  position: relative;
}

#ak-loading .bounce {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  border-radius: 50%;
  background-color: #28bea0;
  opacity: 0.6;
  -webkit-animation: bounce 2.0s infinite ease-in-out;
  animation: bounce 2.0s infinite ease-in-out;
}

#ak-loading .bounce2 {
  -webkit-animation-delay: -1.0s;
  animation-delay: -1.0s;
}

@keyframes bounce {
  0% {
    transform: scale(0.0);
  }
  50% {
    transform: scale(1.0);
  }
  100% {
    transform: scale(0.0);
  }
}

@-webkit-keyframes bounce {
  0% {
    transform: scale(0.0);
  }
  50% {
    transform: scale(1.0);
  }
  100% {
    transform: scale(0.0);
  }
}</style><style>

